def fraesrohrBlechInfo(pair) {
		my info = List();
		my points = List();
		my center = Vector();
		my rotation = Vector();
		my width = 0;
		my type = '';
		my length = Number(PartAttr(pair[0],'hc_length'));
		my dist = RelativePartPos(pair[0], pair[1]);
		my dx = Abs(Round(dist['x']));
		my dy = Abs(Round(dist['y']));
		my dz = Abs(Round(dist['z']));


		if (dy eq 0 and dz eq 0) {
		    width = Round(Abs(dist['x']));
		} else if (dx eq 0 and dz eq 0) {
		    width = Round(Abs(dist['y']));
		} else {
		    width = Round(Abs(dist['z']));
		}

		width = width * 10;

		if (length eq PartAttr(pair[1],'hc_length')) {
		  rotation = Vector(0,0,0);
		  points[0] = VectorSub(PartPos(pair[0]),Vector(0,-length/20,0));
		  points[1] = VectorSub(PartPos(pair[0]),Vector(0,length/20,0));
		  points[2] = VectorSub(PartPos(pair[1]),Vector(0,-length/20,0));
		  points[3] = VectorSub(PartPos(pair[1]),Vector(0,length/20,0));
		} 

		center = call polyCentroid(points);
		type = call dimsToMaybeComp(width, length);

		info['type'] = type;
		info['position'] = center;
		info['rotation'] = rotation;

		return info;

		}
